args.sparql:
SELECT ?attendance WHERE {
  VALUES ?seriesLabel {
    "1975 American League Championship Series"@en
    "2013 American League Championship Series"@en
    "2018 World Series"@en
  }
  ?series rdfs:label ?seriesLabel .
  ?series p:P1346 ?participation .
  ?participation ps:P1346 wd:Q10080 .
  ?game wdt:P1428 ?series .
  ?game wdt:P1497 ?attendance .
} ORDER BY DESC(?attendance) LIMIT 1

SELECT ?attendance WHERE {
  VALUES ?year { 1975 2013 2018 }
  VALUES ?seriesType { wd:Q20527 wd:Q12758 }

  ?series wdt:P31 ?seriesType.
  ?series wdt:P585 ?time.
  FILTER(YEAR(?time) = ?year)
  FILTER( (?seriesType = wd:Q20527 && ?year IN (1975, 2013)) || 
          (?seriesType = wd:Q12758 && ?year = 2018) )

  ?series p:P1346 ?participation.
  ?participation ps:P1346 wd:Q10080.

  ?game wdt:P1428 ?series.
  ?game wdt:P1497 ?attendance.
} ORDER BY DESC(?attendance) LIMIT 1

SELECT ?attendance WHERE {
  VALUES ?seriesLabel {
    "1975 American League Championship Series"@en
    "2013 American League Championship Series"@en
    "2018 World Series"@en
  }
  ?series rdfs:label ?seriesLabel .
  ?series p:P1346 ?participation .
  ?participation ps:P1346 wd:Q10080 .
  ?game wdt:P1428 ?series .
  ?game wdt:P1497 ?attendance .
} ORDER BY DESC(?attendance) LIMIT 1
